import itertools
from math import prod
from time import perf_counter
import random
import math

import tpp_bnb
import tpp
import u_tpp
import polygon_decomposition

from collections.abc import Iterable, Sequence

def path_length(path: Sequence[tuple[float, float]]) -> float:
	return sum(((x2 - x1) ** 2 + (y2 - y1) ** 2) ** 0.5 for (x1, y1), (x2, y2) in zip(path, path[1:]))

def estimate_enumeration(
	start: tuple[float, float], target: tuple[float, float], polygons: Sequence[Sequence[tuple[float, float]]],
	*, max_calls: int = 1000
	) -> tuple[float, int]:
	
	start_time = perf_counter()
	convex_pieces = [polygon_decomposition.decompose(poly) for poly in polygons]

	preprocess_time = perf_counter() - start_time

	possibles = prod(map(len, convex_pieces))

	if possibles < max_calls:
		return tpp.tpp_solve_tracked(start, target, polygons)
	else:

		start_time = perf_counter()
		
		for _ in range(max_calls):
			instance = [random.choice(partition) for partition in convex_pieces]
			u_tpp.tpp_solve(start, target, instance)

		end_time = perf_counter()

		instance_ellapsed = (end_time - start_time) / max_calls
		estimated_time = instance_ellapsed * possibles + preprocess_time
		
		return estimated_time, possibles

def do_tests(
	tests: Sequence[tuple[tuple[float, float], tuple[float, float], Sequence[Sequence[tuple[float, float]]]]],
	*, max_calls: int = 1000
	) -> tuple[list[float], list[int], list[float], list[list[int]]]:

	enumeration_times = []
	bnb_times = []

	enumeration_calls_list = []
	bnb_bound_calls_list = []

	for i, test in enumerate(tests):
		
		print("Running test", i + 1, "of", len(tests), flush=True)

		enumeration_time, enumeration_calls = estimate_enumeration(*test, max_calls=max_calls)
		bnb_time, bnb_calls = tpp_bnb.tpp_solve_tracked(*test)

		enumeration_times.append(enumeration_time)
		bnb_times.append(bnb_time)

		enumeration_calls_list.append(enumeration_calls)
		bnb_bound_calls_list.append(bnb_calls)

	return enumeration_times, enumeration_calls_list, bnb_times, bnb_bound_calls_list

def convert_tour(tour: Iterable[Sequence[tuple[float, float]]]) -> tuple[tuple[float, float], tuple[float, float], Sequence[Sequence[tuple[float, float]]]]:

	minx = min(x for poly in tour for x, _ in poly)
	miny = min(y for poly in tour for _, y in poly)

	maxx = max(x for poly in tour for x, _ in poly)
	maxy = max(y for poly in tour for _, y in poly)

	width = maxx - minx
	height = maxy - miny

	rate = 0.1

	start = (minx - width * rate, miny - height * rate)
	target = (maxx + width * rate, maxy + height * rate)

	return start, target, [poly[:-1][::-1] for poly in tour]

def random_instance(star_count: int, star_points: int) -> tuple[tuple[float, float], tuple[float, float], Sequence[Sequence[tuple[float, float]]]]:
	
	polygons = []

	width = math.isqrt(star_count)
	height = (star_count + width - 1) // width

	centers = random.sample([(x, y) for x in range(width) for y in range(height)], star_count)

	for center in centers:

		polygon = []

		radius = random.uniform(0.25, 0.5)
		angle_step = math.tau / star_points

		for i in range(star_points):

			angle1 = 2 * i * angle_step / 2
			x = center[0] + radius * math.cos(angle1)
			y = center[1] + radius * math.sin(angle1)

			polygon.append((x, y))

			angle2 = (2 * i + 1) * angle_step / 2
			x = center[0] + (radius / 3) * math.cos(angle2)
			y = center[1] + (radius / 3) * math.sin(angle2)

			polygon.append((x, y))

		polygons.append(polygon)

	return (-1.0, -1.0), (width, height), polygons


def main() -> None:

	converted = [convert_tour(tour) for tour in tour_instances]
	stars = [random_instance(5, 10) for _ in range(1)]

	tests_to_do = [
		tests,
		#converted,
		stars,
	]

	run_tests = list(itertools.chain.from_iterable(tests_to_do))

	enumeration_times, enumeration_calls_list, bnb_times, bnb_bound_calls_list = do_tests(run_tests, max_calls=1000)

	ratios1 = [a / b for a, b in zip(enumeration_times, bnb_times)]
	ratios2 = [a / (b[0] + b[1]) for a, b in zip(enumeration_calls_list, bnb_bound_calls_list)]

	ratios1.sort()
	ratios2.sort()

	print([x[2] for x in bnb_bound_calls_list])

	print("Times:", " | ".join(f"{t:.2f}" for t in ratios1))
	print("Calls:", " | ".join(f"{t:.2f}" for t in ratios2))

	print(sum(enumeration_calls_list))
	print(sum(b[0] + b[1] for b in bnb_bound_calls_list))

if __name__ == "__main__":
	main()
